'use client'

import React, {
  createContext,
  useContext,
  useState,
  useCallback,
  useRef,
  useEffect,
  ReactNode,
} from "react"

type WindowWithAudio = Window & {
  AudioContext?: {
    new (contextOptions?: AudioContextOptions): AudioContext
  }
  webkitAudioContext?: {
    new (contextOptions?: AudioContextOptions): AudioContext
  }
}

type AudioContextValue = {
  soundEnabled: boolean
  toggleSound: () => void
  playHoverSound: () => void
  playClickSound: () => void
}

const AudioContextReact = createContext<AudioContextValue | undefined>(
  undefined
)

export function useAudio() {
  const ctx = useContext(AudioContextReact)
  if (!ctx) {
    throw new Error("useAudio must be used within <AudioProvider />")
  }
  return ctx
}

type AudioProviderProps = {
  children: ReactNode
}

export function AudioProvider({ children }: AudioProviderProps) {
  const [soundEnabled, setSoundEnabled] = useState(false)
  const audioContextRef = useRef<AudioContext | null>(null)

  const ensureContext = useCallback(() => {
    if (audioContextRef.current) {
      // garante que tá rodando
      if (audioContextRef.current.state === "suspended") {
        audioContextRef.current.resume()
      }
      return audioContextRef.current
    }

    if (typeof window === "undefined") return null

    const win = window as WindowWithAudio
    const Ctor = win.AudioContext || win.webkitAudioContext
    if (!Ctor) return null

    const ctx = new Ctor()
    audioContextRef.current = ctx

    if (ctx.state === "suspended") {
      ctx.resume()
    }

    return ctx
  }, [])

  const toggleSound = useCallback(() => {
    setSoundEnabled((prev) => {
      const next = !prev
      if (next) {
        // quando ligar o som, garante que o contexto existe e tá rodando
        const ctx = ensureContext()
        if (ctx && ctx.state === "suspended") {
          ctx.resume()
        }
      }
      return next
    })
  }, [ensureContext])

  const playHoverSound = useCallback(() => {
    if (!soundEnabled) return
    const ctx = ensureContext()
    if (!ctx) return

    const now = ctx.currentTime
    const osc = ctx.createOscillator()
    const gain = ctx.createGain()

    osc.connect(gain)
    gain.connect(ctx.destination)

    osc.frequency.setValueAtTime(800, now)
    osc.frequency.exponentialRampToValueAtTime(600, now + 0.05)
    gain.gain.setValueAtTime(0.05, now)
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.08)

    osc.start(now)
    osc.stop(now + 0.08)
  }, [soundEnabled, ensureContext])

  const playClickSound = useCallback(() => {
    if (!soundEnabled) return
    const ctx = ensureContext()
    if (!ctx) return

    const now = ctx.currentTime
    const osc = ctx.createOscillator()
    const gain = ctx.createGain()

    osc.connect(gain)
    gain.connect(ctx.destination)

    osc.frequency.setValueAtTime(1200, now)
    osc.frequency.exponentialRampToValueAtTime(400, now + 0.1)
    gain.gain.setValueAtTime(0.08, now)
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.12)

    osc.start(now)
    osc.stop(now + 0.12)
  }, [soundEnabled, ensureContext])

  useEffect(() => {
    return () => {
      if (audioContextRef.current) {
        audioContextRef.current.close()
      }
    }
  }, [])

  const value: AudioContextValue = {
    soundEnabled,
    toggleSound,
    playHoverSound,
    playClickSound,
  }

  return (
    <AudioContextReact.Provider value={value}>
      {children}
    </AudioContextReact.Provider>
  )
}
